SELECT ROW_NUMBER() OVER (ORDER BY a.reg_dtime ASC) AS rownm a.company_seq, a.company_cd, a.company_name, a.company_phone, a.master_id, b.user_name a.biz_number, a.customs_num, a.reg_dtime, a.upd_dtime, a.use_yn FROM TB_COMPANIES a, TB_USERS b WHERE 1=1 AND a.master_id = b.user_id
ORDER BY ROW_NUMBER() OVER (ORDER BY a.reg_dtime ASC) DESC
LIMIT #{startRow}, #{limit}
